// Extract ticker symbols from natural language question
const question = ($input.first().json.body?.question || $input.first().json.question || '').toLowerCase();
console.log('Question:', question);

// Known ticker mappings for common names
const nameMap = {
  'apple': 'AAPL', 'microsoft': 'MSFT', 'google': 'GOOGL', 'alphabet': 'GOOGL',
  'amazon': 'AMZN', 'meta': 'META', 'facebook': 'META', 'nvidia': 'NVDA',
  'tesla': 'TSLA', 'netflix': 'NFLX', 'berkshire': 'BRK-B',
  'sp500': 'SPY', 's&p 500': 'SPY', 's&p': 'SPY', 'sp 500': 'SPY',
  'nasdaq': 'QQQ', 'dow': 'DIA', 'dow jones': 'DIA', 'russell': 'IWM',
  'qqq': 'QQQ', 'spy': 'SPY', 'dia': 'DIA', 'iwm': 'IWM',
  'gold': 'GLD', 'silver': 'SLV', 'oil': 'USO', 'bitcoin': 'BTC-USD',
  'vix': '^VIX', 'volatility': '^VIX',
  'jpmorgan': 'JPM', 'jp morgan': 'JPM', 'goldman': 'GS', 'morgan stanley': 'MS',
  'visa': 'V', 'mastercard': 'MA', 'paypal': 'PYPL',
  'johnson': 'JNJ', 'pfizer': 'PFE', 'unitedhealth': 'UNH',
  'exxon': 'XOM', 'chevron': 'CVX'
};

// Extract explicit tickers (uppercase 1-5 letter sequences)
const explicitTickers = (question.match(/\b([A-Z]{1,5})\b/g) || []);

// Extract from name map
const mappedTickers = [];
for (const [name, ticker] of Object.entries(nameMap)) {
  if (question.includes(name)) mappedTickers.push(ticker);
}

// Combine, deduplicate, limit to 5
const rawQuestion = $input.first().json.body?.question || $input.first().json.question || '';
const allTickers = [...new Set([
  ...mappedTickers,
  ...(rawQuestion.match(/\b([A-Z]{1,5})\b/g) || [])
])].slice(0, 5);

const tickers = allTickers.length > 0 ? allTickers : ['SPY']; // default to SPY if nothing found
console.log('Tickers to fetch:', tickers);

return [{ json: { tickers, question: rawQuestion, originalQuestion: rawQuestion } }];

const https = require('https');

function fetchQuote(symbol) {
  return new Promise((resolve) => {
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=1d&range=1d`;
    const options = {
      hostname: 'query1.finance.yahoo.com',
      path: `/v8/finance/chart/${encodeURIComponent(symbol)}?interval=1d&range=1d`,
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0',
        'Accept': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          const meta = json?.chart?.result?.[0]?.meta;
          if (!meta) { resolve({ symbol, error: 'No data' }); return; }
          const price = meta.regularMarketPrice;
          const prevClose = meta.chartPreviousClose || meta.previousClose;
          const change = prevClose ? (price - prevClose) : 0;
          const changePct = prevClose ? ((change / prevClose) * 100) : 0;
          const currency = meta.currency || 'USD';
          const marketState = meta.marketState || 'UNKNOWN';
          resolve({
            symbol: meta.symbol || symbol,
            name: meta.shortName || meta.longName || symbol,
            price: price?.toFixed(2),
            change: change?.toFixed(2),
            changePct: changePct?.toFixed(2),
            currency,
            marketState,
            exchange: meta.exchangeName || ''
          });
        } catch(e) {
          resolve({ symbol, error: e.message });
        }
      });
    });
    req.on('error', (e) => resolve({ symbol, error: e.message }));
    req.setTimeout(10000, () => { req.destroy(); resolve({ symbol, error: 'timeout' }); });
    req.end();
  });
}

const { tickers, question } = $input.first().json;
console.log('Fetching quotes for:', tickers);

const quotes = await Promise.all(tickers.map(t => fetchQuote(t)));
console.log('Quotes received:', JSON.stringify(quotes));

return [{ json: { quotes, question } }];

const { quotes, question } = $input.first().json;

// Build a clean readable response
const lines = quotes.map(q => {
  if (q.error) return `**${q.symbol}**: data unavailable`;
  const arrow = parseFloat(q.change) >= 0 ? '▲' : '▼';
  const sign = parseFloat(q.change) >= 0 ? '+' : '';
  const state = q.marketState === 'PRE' ? ' *(pre-market)*' : q.marketState === 'POST' ? ' *(after-hours)*' : '';
  return `**${q.symbol}** (${q.name}) — $${q.price} ${arrow} ${sign}${q.change} (${sign}${q.changePct}%)${state}`;
});

const timestamp = new Date().toLocaleTimeString('en-US', { timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit' });
const content = lines.join('\n') + `\n\n*Prices as of ~${timestamp} ET via Yahoo Finance*`;

return [{ json: { content } }];

